            var modal = new bootstrap.Modal(
                document.getElementById('deleteModal')
            );
            modal.show();
        }

        // Auto-submit search input
        let timer;
        document.getElementById(""searchInput"").addEventListener(""keyup"", function () {
            clearTimeout(timer);
            timer = setTimeout(() => {
                document.getElementById(""searchForm"").submit();
            }, 2000);
        });
    </script>


